// ── Parse the OpenAI response and merge with original form data ──

const openaiOutput = $input.first().json;
const formData = $('Contact Form Webhook').first().json;

// Handle different n8n / OpenAI response formats
const rawText =
  openaiOutput.message?.content ||
  openaiOutput.choices?.[0]?.message?.content ||
  openaiOutput.text ||
  openaiOutput.content ||
  '';

let customerReply, leadSummary;

try {
  // Strip markdown code fences if the model added them
  const cleaned = rawText
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const parsed = JSON.parse(cleaned);
  customerReply = parsed.customerReply;
  leadSummary   = parsed.leadSummary;

} catch (e) {
  // Fallback: plain acknowledgment so the customer always gets a reply
  customerReply =
    `<p>Hi ${formData.firstName},</p>` +
    `<p>Thank you for reaching out! I've received your enquiry about ` +
    `<strong>${formData.service}</strong> and will personally review ` +
    `it and follow up within 24 hours.</p>` +
    `<p>Best,<br>Omkar</p>`;

  leadSummary =
    `⚠️  AI parse failed — review manually.\n\n` +
    `Name: ${formData.firstName} ${formData.lastName}\n` +
    `Email: ${formData.email}\n` +
    `Service: ${formData.service}\n` +
    `Company: ${formData.company}\n\n` +
    `Message:\n${formData.message}`;
}

return [{
  json: {
    ...formData,
    customerReply,
    leadSummary,
  }
}];

